#!/usr/bin/env bash
# Extracts tps/latency from every repetition (*_run{N}.txt) generated by
# run_bench.sh and prints the median per scenario, with the min-max range
# to expose variance, plus the extension's percentage overhead based on
# the medians.
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
RESULTS="$SCRIPT_DIR/results"
SUMMARY="$RESULTS/summary.txt"

extract() {
	# $1 = file, $2 = regex anchored at the start of the line
	grep -E "$2" "$1" 2>/dev/null | head -1 | grep -oE '[0-9]+\.[0-9]+' | head -1
}

# Median of a list of numbers (average of the two middle ones if even).
median_of() {
	if [ "$#" -eq 0 ]; then
		echo "NA"
		return
	fi
	printf '%s\n' "$@" | sort -n | awk '
		{ a[NR] = $1 }
		END {
			if (NR % 2 == 1) printf "%.3f", a[(NR + 1) / 2]
			else printf "%.3f", (a[NR / 2] + a[NR / 2 + 1]) / 2
		}'
}

min_of() { printf '%s\n' "$@" | sort -n | head -1; }
max_of() { printf '%s\n' "$@" | sort -n | tail -1; }

: >"$SUMMARY"
log() {
	echo "$1" | tee -a "$SUMMARY"
}

declare -A MED_TPS

log "$(printf "%-20s %5s %14s %20s %20s" "scenario" "n" "median tps" "tps min-max" "median lat (ms)")"
for scen in noext_persistent noext_reconnect ext_persistent ext_reconnect; do
	tps_vals=()
	lat_vals=()
	for f in "$RESULTS/${scen}"_run*.txt; do
		[ -f "$f" ] || continue
		t=$(extract "$f" '^tps =')
		l=$(extract "$f" '^latency average')
		[ -n "$t" ] && tps_vals+=("$t")
		[ -n "$l" ] && lat_vals+=("$l")
	done

	n=${#tps_vals[@]}
	if [ "$n" -eq 0 ]; then
		log "$(printf "%-20s %5s %14s %20s %20s" "$scen" "0" "NA" "NA" "NA")"
		continue
	fi

	med_tps=$(median_of "${tps_vals[@]}")
	med_lat=$(median_of "${lat_vals[@]}")
	minmax="$(min_of "${tps_vals[@]}")-$(max_of "${tps_vals[@]}")"
	MED_TPS[$scen]=$med_tps

	log "$(printf "%-20s %5s %14s %20s %20s" "$scen" "$n" "$med_tps" "$minmax" "$med_lat")"
done

log ""
log "==> extension overhead (median tps with ext vs without ext)"
for mode in persistent reconnect; do
	noext="${MED_TPS[noext_$mode]:-NA}"
	ext="${MED_TPS[ext_$mode]:-NA}"
	if [ "$noext" != "NA" ] && [ "$ext" != "NA" ]; then
		log "$(awk -v m="$mode" -v n="$noext" -v e="$ext" 'BEGIN {
			delta = (e - n) / n * 100
			printf "%-12s tps without ext=%10.2f  tps with ext=%10.2f  delta=%+.2f%%", m, n, e, delta
		}')"
	fi
done
